function formatCurrency(val) {
  if (val >= 1000000) return `$${(val / 1000000).toFixed(1)}M`;
  if (val >= 1000) return `$${(val / 1000).toFixed(0)}K`;
  return `$${val.toLocaleString()}`;
}

function formatFull(val) {
  return `$${val.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;
}

function AnimatedNumber({ value, format = "currency", duration = 600 }) {
  const [display, setDisplay] = useState(value);
  const ref = useRef(null);
  const prevVal = useRef(value);

  useEffect(() => {
    const start = prevVal.current;
    const end = value;
    const startTime = performance.now();
    function tick(now) {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplay(start + (end - start) * eased);
      if (progress < 1) ref.current = requestAnimationFrame(tick);
    }
    ref.current = requestAnimationFrame(tick);
    prevVal.current = value;
    return () => cancelAnimationFrame(ref.current);
  }, [value, duration]);

  if (format === "currency") return formatFull(Math.round(display));
  if (format === "short") return formatCurrency(Math.round(display));
  return Math.round(display).toLocaleString();
}

function SliderInput({ label, value, onChange, suffix, description, min = 0, max, step = 1 }) {
  const isPercent = suffix === "%";
  const pct = ((value - min) / (max - min)) * 100;

  const [editing, setEditing] = useState(false);
  const [editText, setEditText] = useState("");

  const displayVal = isPercent
    ? `${(value * 100).toFixed(2)}%`
    : suffix === "$"
      ? `$${Number(value).toLocaleString()}`
      : Number(value).toLocaleString();

  const handleClick = () => {
    setEditing(true);
    setEditText(isPercent ? (value * 100).toFixed(2) : String(value));
  };

  const handleBlur = () => {
    setEditing(false);
    let parsed = parseFloat(editText.replace(/[^0-9.]/g, ""));
    if (isNaN(parsed)) return;
    if (isPercent) parsed = parsed / 100;
    parsed = Math.max(min, Math.min(max, parsed));
    onChange(parsed);
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") e.target.blur();
    if (e.key === "Escape") { setEditing(false); }
  };

  return (
    <div style={{ marginBottom: 22 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 8 }}>
        <label style={{ fontSize: 13, fontWeight: 500, color: V.text, fontFamily: "'DM Sans', sans-serif" }}>
          {label}
        </label>
        {editing ? (
          <input
            autoFocus
            type="text"
            value={editText}
            onChange={(e) => setEditText(e.target.value)}
            onBlur={handleBlur}
            onKeyDown={handleKeyDown}
            style={{
              fontSize: 15, fontWeight: 700, color: V.purpleBright,
              fontFamily: "'JetBrains Mono', monospace",
              background: "rgba(190,130,243,0.1)", border: `1px solid ${V.purple}`,
              borderRadius: 6, padding: "2px 8px", width: 120, textAlign: "right",
              outline: "none",
            }}
          />
        ) : (
          <span
            onClick={handleClick}
            title="Click to type a value"
            style={{
              fontSize: 15, fontWeight: 700, color: V.purpleBright,
              fontFamily: "'JetBrains Mono', monospace",
              cursor: "pointer", borderBottom: `1px dashed ${V.purpleDim}`,
              paddingBottom: 1,
            }}>
            {displayVal}
          </span>
        )}
      </div>
      <div style={{ position: "relative" }}>
        <input
          type="range" min={min} max={max} step={step} value={value}
          onChange={(e) => onChange(parseFloat(e.target.value))}
          style={{
            width: "100%", height: 5, appearance: "none", outline: "none", cursor: "pointer",
            background: `linear-gradient(to right, ${V.purple} 0%, ${V.purple} ${pct}%, rgba(130,80,220,0.15) ${pct}%, rgba(130,80,220,0.15) 100%)`,
            borderRadius: 3,
          }}
        />
      </div>
      <p style={{ fontSize: 11, color: V.textDim, marginTop: 5, fontFamily: "'DM Sans', sans-serif", lineHeight: 1.4 }}>{description}</p>
    </div>
  );
}

function MetricCard({ label, value, color = V.purple, glow, sub }) {
  return (
    <div style={{
      background: glow || V.purpleGlow,
      border: `1px solid ${color}30`,
      borderRadius: 14, padding: "20px 22px",
      flex: 1, minWidth: 200,
      position: "relative", overflow: "hidden",
    }}>
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0, height: 1,
        background: `linear-gradient(90deg, transparent, ${color}44, transparent)`,
      }} />
      <div style={{ fontSize: 10, textTransform: "uppercase", letterSpacing: 1.4, color: V.textMuted, marginBottom: 8, fontFamily: "'DM Sans', sans-serif", fontWeight: 600 }}>
        {label}
      </div>
      <div style={{
        fontSize: 28, fontWeight: 800, color,
        fontFamily: "'JetBrains Mono', monospace", lineHeight: 1.1,
      }}>
        <AnimatedNumber value={value} />
      </div>
      {sub && <div style={{ fontSize: 11, color: V.textDim, marginTop: 6, fontFamily: "'DM Sans', sans-serif" }}>{sub}</div>}
    </div>
  );
}

function ComparisonBar({ label, value, maxValue, color, icon }) {
  const pct = maxValue > 0 ? Math.min((value / maxValue) * 100, 100) : 0;
  return (
    <div style={{ marginBottom: 18 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 7 }}>
        <span style={{ fontSize: 13, color: V.text, fontFamily: "'DM Sans', sans-serif" }}>{icon} {label}</span>
        <span style={{ fontSize: 14, fontWeight: 700, color, fontFamily: "'JetBrains Mono', monospace" }}>
          <AnimatedNumber value={value} />
        </span>
      </div>
      <div style={{ height: 6, background: "rgba(130,80,220,0.08)", borderRadius: 3, overflow: "hidden" }}>
        <div style={{
          height: "100%", width: `${pct}%`,
          background: `linear-gradient(90deg, ${color}cc, ${color})`,
          borderRadius: 3, transition: "width 0.6s cubic-bezier(0.22,1,0.36,1)",
          boxShadow: `0 0 12px ${color}33`,
        }} />
      </div>
    </div>
  );
}

