  const grossFeeRevenue = monthlyVolume * feePercent;
  const velvetMonthlyFee = grossFeeRevenue * revShare;
  const netMonthlyRevenue = grossFeeRevenue - velvetMonthlyFee - maintenanceFee;
  const annualNetRevenue = netMonthlyRevenue * 12;

